   public void setupAnim(T entity, float limbSwing, float limbSwingAmount, float ageInTicks, float netHeadYaw, float headPitch) {
      this.right_leg10.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.left_legs11.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.left_legs12.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.right_legs11.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.right_legs12.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.head.yRot = netHeadYaw / 57.295776F;
      this.head.xRot = headPitch / 57.295776F;
      this.right_leg9.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.right_leg7.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.right_leg8.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.left_leg7.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.left_leg8.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.left_leg9.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.left_leg10.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
   }
